import Combine

// O modelo básico:
// Publisher — fonte de valores ao longo do tempo
// Subscriber — consome os valores
// Operator — transforma os valores entre Publisher e Subscriber

// Publisher simples:
let publicador = [1, 2, 3, 4, 5].publisher

// Subscriber com sink:
let cancelavel = publicador
    .filter { $0 % 2 == 0 }    // só pares
    .map { $0 * 10 }            // multiplica por 10
    .sink { valor in
        print(valor)  // imprime: 20, 40
    }

// PassthroughSubject — evento sem estado:
let eventoToque = PassthroughSubject<Void, Never>()

// Emitir um evento:
eventoToque.send(())

// CurrentValueSubject — estado com histórico:
let buscaAtual = CurrentValueSubject<String, Never>("")
buscaAtual.value  // "" — valor atual
buscaAtual.send("Swift")  // muda para "Swift"

// Exemplo de busca com debounce:
let cancelavel = buscaAtual
    .debounce(for: .milliseconds(300), scheduler: RunLoop.main)  // aguarda 300ms sem mudança
    .removeDuplicates()  // ignora se o valor não mudou
    .sink { texto in
        Task {
            await buscar(query: texto)
        }
    }

// Pipeline de validação de formulário:
let emailValido = $email  // @Published String
    .map { $0.contains("@") && $0.contains(".") }

let senhaValida = $senha
    .map { $0.count >= 8 }

// Combina dois publishers — botão ativo só quando os dois são válidos:
let podeEnviar = emailValido
    .combineLatest(senhaValida)
    .map { email, senha in email && senha }

let cancelavel = podeEnviar
    .receive(on: RunLoop.main)
    .assign(to: &$botaoAtivo)  // atualiza @Published diretamente

// flatMap para chamadas de rede em sequência:
let resultados = $busca
    .debounce(for: .milliseconds(300), scheduler: RunLoop.main)
    .flatMap { query in
        APIService.buscar(query: query)
            .catch { _ in Just([]) }  // em caso de erro, retorna vazio
    }

class BuscaViewModel: ObservableObject {
    @Published var resultados: [Item] = []
    @Published var busca = ""

    private var cancelaveis = Set<AnyCancellable>()  // mantém subscriptions vivas

    init() {
        $busca
            .debounce(for: .milliseconds(300), scheduler: RunLoop.main)
            .removeDuplicates()
            .sink { [weak self] texto in  // [weak self] evita retain cycle
                guard let self else { return }
                Task {
                    await self.buscar(query: texto)
                }
            }
            .store(in: &cancelaveis)  // armazena no Set — subscription ativa
    }

    // Quando BuscaViewModel é desalocado, cancelaveis é desalocado
    // e todas as subscriptions são canceladas automaticamente
}

// Convertendo Publisher em AsyncSequence:
for await valor in buscaAtual.values {
    print("Novo valor: \(valor)")  // async/await sobre um Publisher
}

// Ou converter para async com .first():
let primeiroValor = try await URLSession.shared
    .dataTaskPublisher(for: url)
    .value  // converte Publisher para async

